storage "raft" {
  path    = "/opt/vault/data"
  node_id = "vault-1"

  retry_join {
    leader_api_addr = "https://vault-1.internal:8200"
  }
  retry_join {
    leader_api_addr = "https://vault-2.internal:8200"
  }
  retry_join {
    leader_api_addr = "https://vault-3.internal:8200"
  }
}

cluster_addr = "https://vault-1.internal:8201"
api_addr     = "https://vault-1.internal:8200"

seal "awskms" {
  region     = "us-east-1"
  kms_key_id = "alias/vault-unseal"
}

# Read the app's own KV secrets only:
path "secret/data/myapp/*" {
  capabilities = ["read"]
}

# Pull dynamic read-only DB creds:
path "database/creds/myapp-ro" {
  capabilities = ["read"]
}

# Everything else is denied because it is not listed.

telemetry {
  prometheus_retention_time = "24h"
  disable_hostname          = true
}
